        require(msg.sender == owner, "Caller is not the owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function flipSaleState() external onlyOwner {
        if (!SALE_ACTIVE && !PRESALE_ACTIVE) {
            PRESALE_ACTIVE = true;
        } else if (SALE_ACTIVE) {
            SALE_ACTIVE = false;
            PRESALE_ACTIVE = false;
        } else {
            PRESALE_ACTIVE = false;
            SALE_ACTIVE = true;
        }
    }

    function reserveApes(address[] calldata addresses, uint256[] calldata amounts) external onlyOwner {
        require(addresses.length == amounts.length, "Input arrays must have same length");
